// ========================================
// GL365 Google Reviews Normalizer
// ========================================
// Filters to only NEW reviews (since last poll) and normalizes.

const input = $input.first().json;
const reviews = input.reviews || [];

// Get the last poll timestamp from static data (or default to 1 hour ago)
const lastPoll = $getWorkflowStaticData('global').lastPollTime || new Date(Date.now() - 3600000).toISOString();

// Filter to only new reviews
const newReviews = reviews.filter(r => {
  const reviewTime = r.updateTime || r.createTime;
  return reviewTime && new Date(reviewTime) > new Date(lastPoll);
});

// Update last poll timestamp
$getWorkflowStaticData('global').lastPollTime = new Date().toISOString();

if (newReviews.length === 0) {
  // No new reviews — stop the workflow
  return [];
}

// Normalize each new review
return newReviews.map(review => {
  const rating = review.starRating || '';
  const ratingNum = { 'ONE': 1, 'TWO': 2, 'THREE': 3, 'FOUR': 4, 'FIVE': 5 }[rating] || 0;
  const reviewerName = review.reviewer?.displayName || 'Anonymous';
  const comment = review.comment || '(no text)';

  let sentiment = 'neutral';
  if (ratingNum >= 4) sentiment = 'positive';
  if (ratingNum <= 2) sentiment = 'negative';

  let importance = 'normal';
  if (ratingNum <= 2) importance = 'critical'; // Bad reviews need attention
  if (ratingNum === 5 && comment.length > 50) importance = 'high'; // Great reviews worth noting

  return {
    json: {
      tenant_id: '', // Set per client deployment
      contact_phone: '',
      contact_email: '',
      contact_name: reviewerName,
      source: 'google_reviews',
      event_type: 'review_posted',
      raw_summary: `${ratingNum}-star Google review by ${reviewerName}: "${comment.substring(0, 150)}"`,
      raw_data: review,
      sentiment,
      importance,
      rating: ratingNum,
      review_text: comment,
      reviewer_name: reviewerName,
      review_id: review.reviewId || review.name
    }
  };
});

const input = $input.first().json;
const prevData = $('Filter & Normalize New Reviews').first().json;
let summary = '';
try { summary = input.choices?.[0]?.message?.content || prevData.raw_summary; } catch { summary = prevData.raw_summary; }
return [{ json: { ...prevData, summary: summary.trim().replace(/^["']|["']$/g, '') } }];

